<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="95" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Please List Properties You Own</p>
      <p slot="message">
        We are almost at the end. We just need to collect your existing properties information to finalize your mortgage assesment. If you own properties, please list them all in the address blocks provided.
      </p>
      <p slot="message" class="is-size-5 is-size-6-mobile">
        This page inquires about the following form items:
      </p>
      <ul slot="list">
        <li>The value and type of property</li>
        <li>Property taxes</li>
        <li>The address of the property</li>
        <li>If the property is used and/or mortgaged</li>
      </ul>
    </message-modal>
    <div class="container">
      <div class="box">

        <div class="columns is-centered">
          <div class="column is-half is-one-third-desktop">
            <b-field label="Property value" :addons="false" class="info">
              <b-tooltip label="What is this property currently worth?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input v-model="propertyValue" icon="dollar-sign" placeholder="CAD" expanded></b-input>
            </b-field>
          </div>
          <div class="column is-half is-one-third-desktop">
