                  <b-field label="Mortgage amount" :addons="false" class="info">
                    <b-tooltip label="What are your mortgage payments?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                      <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                    </b-tooltip>
                    <b-field>
                      <b-input v-model="mortgagePayment" icon="hand-holding-usd" placeholder="CAD" expanded></b-input>
                      <b-select placeholder="CAD" icon="dollar-sign" v-model="mortgagePaymentType">
                        <option value="monthly">Monthly</option>
                        <option value="bi-weekly">Bi-weekly</option>
                      </b-select>
                    </b-field>
                  </b-field>
                </div>
                <div class="column is-half">
                  <b-field label="Mortgage rate" :addons="false" class="info">
                    <b-tooltip label="What is your mortgage rate?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                      <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                    </b-tooltip>
                    <b-field>
                      <b-input v-model="mortgageRate" icon="percent" placeholder="CAD" expanded></b-input>
                      <b-select placeholder="Type" icon="signature" v-model="mortgageRateType">
                        <option value="fixed">Fixed</option>
                        <option value="variable">Variable</option>
                      </b-select>
                    </b-field>
                  </b-field>
                </div>
                <div class="column is-half">
                  <b-field label="Mortgage lender" :addons="false" class="info">
