                      <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                    </b-tooltip>
                    <b-input v-model="mortgageLender" icon="university" placeholder="My mortgage is with" type="text" expanded></b-input>
                  </b-field>
                </div>
              </div>
            </div>
          </div>
        </transition>

        <address-block message="Your property address" icon="building" :form="$store.state.PropertiesForm.address"></address-block>

