  },
  computed: {
    propertyValue: {
      get() {
        return this.$store.state.PropertiesForm.propertyValue;
      },
      set(val) {
        this.$store.state.PropertiesForm.propertyValue = val;
      }
    },
    propertyType: {
      get() {
        return this.$store.state.PropertiesForm.propertyType;
      },
      set(val) {
        this.$store.state.PropertiesForm.propertyType = val;
      }
    },
    propertyTaxes: {
      get() {
        return this.$store.state.PropertiesForm.propertyTaxes;
      },
      set(val) {
        this.$store.state.PropertiesForm.propertyTaxes = val;
      }
