    mortgaged: {
      get() {
        return this.$store.state.PropertiesForm.mortgaged;
      },
      set(val) {
        this.$store.state.PropertiesForm.mortgaged = val;
      }
    },
    rentalIncome: {
      get() {
        return this.$store.state.PropertiesForm.rentalIncome;
      },
      set(val) {
        this.$store.state.PropertiesForm.rentalIncome = val;
      }
    },
    mortgagePayment: {
      get() {
        return this.$store.state.PropertiesForm.mortgagePayment;
      },
      set(val) {
        this.$store.state.PropertiesForm.mortgagePayment = val;
      }
    },
    mortgageRate: {
      get() {
        return this.$store.state.PropertiesForm.mortgageRate;
      },
      set(val) {
        this.$store.state.PropertiesForm.mortgageRate = val;
      }
    },
    mortgageRateType: {
      get() {
        return this.$store.state.PropertiesForm.mortgageRateType;
      },
      set(val) {
        this.$store.state.PropertiesForm.mortgageRateType = val;
      }
    },
    mortgagePaymentType: {
      get() {
        return this.$store.state.PropertiesForm.mortgagePaymentType;
      },
      set(val) {
        this.$store.state.PropertiesForm.mortgagePaymentType = val;
      }
    },
    mortgageLender: {
      get() {
        return this.$store.state.PropertiesForm.mortgageLender;
      },
      set(val) {
        this.$store.state.PropertiesForm.mortgageLender = val;
      }
    }
  },
  components: {
    addressBlock
  }
};
</script>
