<template>
  <div>
    <div key="random_c12242" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Are you self-employed?" :addons="false" class="info">
          <b-tooltip label="As per your tax statements" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-radio-button class="full-radio" :native-value="true" v-model="selfEmployed" @input="$emit('routechange')">
              <b-icon icon="check-circle"></b-icon>&thinsp;
              Yes I am
            </b-radio-button>
            <b-radio-button class="full-radio" :native-value="false" v-model="selfEmployed" @input="$emit('routechange')">
              <b-icon icon="times-circle"></b-icon>&thinsp;
              No I'm not
            </b-radio-button>
          </b-field>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Time on the job" :addons="false" class="info">
          <b-tooltip label="How long have you acted in your current capacity?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-input v-model="timeAtJob" type="text" expanded icon="clock" placeholder="I worked here for" v-debounce:600="checkYears"></b-input>
            <b-radio-button name="span" native-value="years" v-model="timeAtJobSpan" @input="checkYears">
              years
            </b-radio-button>
            <b-radio-button name="span" native-value="months" v-model="timeAtJobSpan" @input="checkYears">
              months
            </b-radio-button>
          </b-field>
        </b-field>
      </div>
    </div>

    <div key="random_23sj34f" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Company name" :addons="false" class="info">
          <b-tooltip label="What is the registered name of the company you work for?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input v-model="companyName" expanded icon="briefcase" placeholder="I work for"></b-input>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Time in the industry" :addons="false" class="info">
          <b-tooltip label="How long have worked in your current industry?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input expanded icon="industry" placeholder="Years"></b-input>
        </b-field>
      </div>
    </div>

    <div key="random_cvk42" class="columns is-centered">
      <div class="column is-one-third-desktop">
        <b-field label="Occupation" :addons="false" class="info">
          <b-tooltip label="What is your role at the company?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input expanded icon="user-tie" placeholder="I'm a"></b-input>
        </b-field>
      </div>
      <div class="column is-one-third-desktop">
        <b-field label="Income" :addons="false" class="info">
          <b-tooltip label="Please input your annual or hourly rate." position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-field>
            <b-input v-model="income" placeholder="CAD" icon="dollar-sign" expanded></b-input>
            <b-select v-model="incomePer" icon="slash" placeholder="Per">
              <option value="hour">hour</option>
              <option value="year">year</option>
            </b-select>
          </b-field>
        </b-field>
      </div>
    </div>

    <transition-group name="fadeUp" mode="out-in">
      <div key="random_lz9z9z" class="columns is-centered" v-if="additionalWorkFields">
        <div class="column is-one-third-desktop">
          <b-field label="Previous employer" :addons="false" class="info">
            <b-tooltip label="The legal name of your prior employer" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-input expanded icon="briefcase" placeholder="I worked for"></b-input>
          </b-field>
        </div>
        <div class="column is-one-third-desktop">
          <b-field label="Previous occupation" :addons="false" class="info">
            <b-tooltip label="Your occupation at the prior company" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-input expanded icon="user-tie" placeholder="I worked as"></b-input>
          </b-field>
        </div>
      </div>

      <div key="random_llkz1z" class="columns is-centered" v-if="additionalWorkFields">
        <div class="column is-one-third-desktop">
          <b-field label="Previous employer contact" :addons="false" class="info">
            <b-tooltip label="Any way to contact your prior employer. Phone number preferred." position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-input expanded icon="phone-square" placeholder="Please contact"></b-input>
          </b-field>
        </div>
        <div class="column is-one-third-desktop">
          <b-field label="Time on the previous job" :addons="false" class="info">
            <b-tooltip label="How long did you work for the prior employer?" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-input expanded icon="briefcase" placeholder="Years"></b-input>
          </b-field>
        </div>
      </div>
    </transition-group>

    <address-block key="random_75lkj4j" :form="$store.state.CoApplicantForm.EmploymentForm.address" icon="hotel" message="Address of the company you work for"></address-block>

  </div>
</template>

<script>
import addressBlock from "../components/address-block.vue";
export default {
  data() {
    return {
      additionalWorkFields: false
    };
  },
  components: {
    addressBlock
  },
  methods: {
    checkYears() {
      if (this.timeAtJobSpan === null || this.timeAtJob === null) {
        return;
      } else if (this.timeAtJobSpan === "months") {
        parseFloat(this.timeAtJob) / 12 < 3
          ? (this.additionalWorkFields = true)
          : (this.additionalWorkFields = false);
      } else {
        parseFloat(this.timeAtJob) < 3
          ? (this.additionalWorkFields = true)
          : (this.additionalWorkFields = false);
      }
    }
  },
  computed: {
    selfEmployed: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.selfEmployed;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.selfEmployed = val;
      }
    },
    companyName: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.companyName;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.companyName = val;
      }
    },
    employerName: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.employerName;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.employerName = val;
      }
    },
    title: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.title;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.title = val;
      }
    },
    timeAtJobSpan: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.timeAtJobSpan;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.timeAtJobSpan = val;
      }
    },
    income: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.income;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.income = val;
      }
    },
    incomePer: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.incomePer;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.incomePer = val;
      }
    },
    timeAtIndustry: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.timeAtIndustry;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.timeAtIndustry = val;
      }
    },
    timeAtJob: {
      get() {
        return this.$store.state.CoApplicantForm.EmploymentForm.timeAtJob;
      },
      set(val) {
        this.$store.state.CoApplicantForm.EmploymentForm.timeAtJob = val;
      }
    }
  }
};
</script>
